SELECT count(*) FROM commits WHERE repo_name IN (
    SELECT DISTINCT repo_name
    FROM query_sqlite(
        db_name = 'metadata_database',
        sql = 'SELECT DISTINCT repo_name FROM languages WHERE language_description LIKE \'%Shell%\' INTERSECT SELECT DISTINCT repo_name FROM licenses WHERE license = \'apache-2.0\''
    ).repo_name
) AND length(message) < 1000 AND substr(message, 1, 5) NOT IN ('merge', 'Update', 'Test');

