SELECT count(*) FROM commits WHERE repo_name IN (
    SELECT repo_name FROM (
        SELECT DISTINCT l.repo_name
        FROM query_sqlite(
            db_name = 'metadata_database',
            sql = 'SELECT repo_name FROM languages WHERE language_description LIKE \'%Shell%\''
        ) AS l
        INNER JOIN query_sqlite(
            db_name = 'metadata_database',
            sql = 'SELECT repo_name FROM licenses WHERE license = \'apache-2.0\''
        ) AS lic ON l.repo_name = lic.repo_name
    )
) AND length(message) < 1000 AND substr(message, 1, 5) NOT IN ('merge', 'Update', 'Test');

